parameters.script:
const items = $input.all();
const peopleMap = {};

for (const item of items) {
  const raw = item.json.properties_value || item.json;

  const nomeArr = raw.Nome || raw.title || [];
  const nome = Array.isArray(nomeArr)
    ? nomeArr.map(t => t.plain_text || t.text?.content || '').join('')
    : (nomeArr.plain_text || nomeArr);

  if (!nome) continue;

  const cargoArr = raw.Cargo || [];
  const cargos = Array.isArray(cargoArr)
    ? cargoArr.map(c => c.name || c).filter(Boolean)
    : [cargoArr].filter(Boolean);

  const projetoArr = raw.Projeto || [];
  const projetos = Array.isArray(projetoArr)
    ? projetoArr.map(p => p.name || p).filter(Boolean)
    : [projetoArr].filter(Boolean);

  const gestorArr = raw.Gestor || [];
  let gestor = '';
  if (Array.isArray(gestorArr)) {
    gestor = gestorArr.map(t => t.plain_text || t.text?.content || '').join('');
  } else {
    gestor = gestorArr;
  }

  if (!peopleMap[nome]) {
    peopleMap[nome] = {
      nome,
      cargos: [],
      projetos: [],
      gestor
    };
  }

  for (const c of cargos) {
    if (!peopleMap[nome].cargos.includes(c)) {
      peopleMap[nome].cargos.push(c);
    }
  }

  for (const p of projetos) {
    if (!peopleMap[nome].projetos.includes(p)) {
      peopleMap[nome].projetos.push(p);
    }
  }

  if (gestor && !peopleMap[nome].gestor) {
    peopleMap[nome].gestor = gestor;
  }
}

const people = Object.values(peopleMap);
const nodes = [];
const edges = [];

for (const p of people) {
  const cargoLabel = p.cargos.join(', ') || 'Sem cargo';
  nodes.push({
    id: p.nome,
    data: {
      label: p.nome + '\n' + cargoLabel,
      cargo: cargoLabel,
      projetos: p.projetos
    }
  });

  if (p.gestor) {
    edges.push({
      id: p.gestor + '-' + p.nome,
      source: p.gestor,
      target: p.nome
    });
  }
}

return [{ json: { nodes, edges } }];
